#include <bits/stdc++.h>
#define int long long
using namespace std;
const int N = 10005;
int n;
double g[N];
double f[N];
signed main () {
	ios::sync_with_stdio (0);
	cin.tie (0), cout.tie (0);
	cin >> n;
	for (int i = n - 1; ~i; i--) {
		f[i] = f[i + 1] + (1.0 * n) / (1.0 * (n - i));
		g[i] = (1.0 * i) / (1.0 * (n - i)) * (f[i] + 1) + g[i + 1] + f[i + 1] + 1;
	}
	cout << fixed << setprecision (2) << g[0];
	return 0; 
}
